import Seo from '@/component/seo'
import Toc from '@/component/toc'
import type { TocItemData } from '@/component/toc'
import useActivatedIdentifier from '@/core/hook/useActivatedIdentifier'
import {
  createMarkdownNodesRenderer,
  customRendererMap,
  useCodeRunners,
} from '@kyokuya/react-markdown'
import type {
  Definition,
  EcmaImport,
  FootnoteDefinition,
  HeadingToc,
  HeadingTocNode,
  Root,
} from '@yozora/ast'
import { useRendererMap } from '@yozora/react-markdown'
import type { APlayerOptions } from 'aplayer'
import { graphql } from 'gatsby'
import React, { useMemo } from 'react'
import BlogLayout from '../layout'
import Comment from '../layout/comment'
import type { PostItem } from '../layout/search-panel'
import PostContent from './context'

export interface BlogPostContext {
  /**
   * Url of pagination pages.
   */
  paginationUrl: string
  /**
   * Home url
   * @default '/'
   */
  homeUrl?: string
}

export interface PostLayoutProps {
  data: {
    content: {
      title: string
      description: string
      createAt: string
      updateAt: string
      timeToRead: string
      toc: HeadingToc
      ast: Root
      categories: string[][]
      tags: string[]
      ecmaImports: EcmaImport[]
      definitionMap: Record<string, Definition>
      footnoteDefinitionMap: Record<string, FootnoteDefinition>
      frontmatter2: {
        aplayer?: APlayerOptions
        wechatThumbnail?: string
      }
      fields: {
        slug: string
      }
    }
    previous?: {
      title: string
      fields: {
        slug: string
      }
    }
    next?: {
      title: string
      fields: {
        slug: string
      }
    }
    postItems: {
      nodes: PostItem[]
    }
  }
  pageContext: BlogPostContext
}

/**
 * Render a blog post.
 *
 * @param props
 * @returns
 */
export default function PostLayout(props: PostLayoutProps): React.ReactElement {
  const {
    title,
    createAt,
    timeToRead,
    description,
    toc,
    tags,
    ast,
    ecmaImports,
    definitionMap,
    footnoteDefinitionMap,
    frontmatter2,
    fields,
  } = props.data.content!
  const { slug } = fields!
  const { previous, next } = props.data
  const postItems = (props.data.postItems.nodes ?? []) as PostItem[]
  const { paginationUrl } = props.pageContext
  const codeRunners = useCodeRunners(ecmaImports)
  const rendererMap = useRendererMap(customRendererMap, codeRunners)

  const {
    activatedIdentifier,
    refreshActivatedIdentifier,
    pauseWatchingScroll,
  } = useActivatedIdentifier('yozora-heading--toc', 0)

  const tocNodes = useMemo<TocItemData[]>((): TocItemData[] => {
    const results: TocItemData[] = []
    const renderNodes = createMarkdownNodesRenderer(
      rendererMap,
      definitionMap,
      footnoteDefinitionMap,
    )
    function collectTocData(node: HeadingTocNode, cur: number): void {
      const data: TocItemData = {
        depth: cur,
        identifier: encodeURIComponent(node.identifier),
        title: renderNodes(node.contents),
      }
      results.push(data)
      if (node.children != null) {
        node.children.forEach(node => collectTocData(node, cur + 1))
      }
    }

    toc.children.forEach(node => collectTocData(node, 1))
    return results
  }, [toc.children, rendererMap, definitionMap, footnoteDefinitionMap])

  return (
    <BlogLayout
      onScroll={refreshActivatedIdentifier}
      paginationUrl={paginationUrl}
      postItems={postItems}
      head={
        <React.Fragment>
          <Seo title={title} description={description} />
        </React.Fragment>
      }
      content={
        <PostContent
          title={title}
          createAt={createAt}
          timeToRead={timeToRead}
          tags={tags}
          ast={ast}
          ecmaImports={ecmaImports}
          definitionMap={definitionMap}
          footnoteDefinitionMap={footnoteDefinitionMap}
          slug={slug}
          aplayer={frontmatter2.aplayer}
          previous={previous}
          next={next}
        />
      }
      footer={<Comment />}
      nav={
        tocNodes.length > 0 && (
          <Toc
            activatedIdentifier={activatedIdentifier}
            nodes={tocNodes}
            pauseWatchingScroll={pauseWatchingScroll}
          />
        )
      }
    />
  )
}

export const query = void graphql`
query PostBySlug(
  $contentType: String!
  $id: String!
  $previousPostId: String
  $nextPostId: String
) {
  content: markdownYozora(id: { eq: $id }) {
    title
    description
    createAt(formatString: "MMMM DD, YYYY")
    updateAt(formatString: "MMMM DD, YYYY")
    timeToRead(formatString: "m[min] s[s]")
    frontmatter2 {
      aplayer
      wechatThumbnail
    }
    toc {
      children
    }
    categories
    tags
    ast
    ecmaImports
    definitionMap
    footnoteDefinitionMap(preferReferences: true)
    fields {
      slug
    }
  }
  previous: markdownYozora(id: { eq: $previousPostId }) {
    title
    fields {
      slug
    }
  }
  next: markdownYozora(id: { eq: $nextPostId }) {
    title
    fields {
      slug
    }
  }
  postItems: allMarkdownYozora(
    filter: { fields: { contentType: { eq: $contentType } } }
  ) {
    nodes {
      title
      createAt(formatString: "YYYY-MM-DD")
      tags
      fields {
        slug
      }
    }
  }
}
`
